1	/*
2	* @info Vector Load Unit
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module vmu_ld_eng #(
11	    parameter int REQ_DATA_WIDTH     = 256,
12	    parameter int VECTOR_REGISTERS   = 32 ,
13	    parameter int VECTOR_LANES       = 8  ,
14	    parameter int DATA_WIDTH         = 32 ,
15	    parameter int ADDR_WIDTH         = 32 ,
16	    parameter int MICROOP_WIDTH      = 5  ,
17	    parameter int VECTOR_TICKET_BITS = 4
18	) (
19	    input  logic                                clk                ,
20	    input  logic                                rst_n              ,
21	    //Input Interface
22	    input  logic                                valid_in           ,
23	    input  memory_remapped_v_instr              instr_in           ,
24	    output logic                                ready_o            ,
25	    //RF read Interface (for `OP_INDEXED stride)
26	    output logic [$clog2(VECTOR_REGISTERS)-1:0] rd_addr_o          ,
27	    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0] rd_data_i          ,
28	    input  logic                                rd_pending_i       ,
29	    input  logic [      VECTOR_TICKET_BITS-1:0] rd_ticket_i        ,
30	    //RF write Interface
31	    output logic                                wrtbck_req_o       ,
32	    input  logic                                wrtbck_grant_i     ,
33	    output logic [            VECTOR_LANES-1:0] wrtbck_en_o        ,
34	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_o       ,
35	    output logic [ VECTOR_LANES*DATA_WIDTH-1:0] wrtbck_data_o      ,
36	    output logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_o    ,
37	    //RF Writeback Probing Interface
38	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_a_o     ,
39	    input  logic                                wrtbck_locked_a_i  ,
40	    input  logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_a_i  ,
41	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_b_o     ,
42	    input  logic                                wrtbck_locked_b_i  ,
43	    input  logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_b_i  ,
44	    //Unlock Interface
45	    output logic                                unlock_en_o        ,
46	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_a_o     ,
47	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_b_o     ,
48	    output logic [      VECTOR_TICKET_BITS-1:0] unlock_ticket_o    ,
49	    //Request Interface
50	    input  logic                                grant_i            ,
51	    output logic                                req_en_o           ,
52	    output logic [              ADDR_WIDTH-1:0] req_addr_o         ,
53	    output logic [           MICROOP_WIDTH-1:0] req_microop_o      ,
54	    output logic [  $clog2(REQ_DATA_WIDTH/8):0] req_size_o         ,
55	    output logic [      $clog2(VECTOR_LANES):0] req_ticket_o       ,
56	    // Incoming Data from Cache
57	    input  logic                                resp_valid_i       ,
58	    input  logic [      $clog2(VECTOR_LANES):0] resp_ticket_i      ,
59	    input  logic [  $clog2(REQ_DATA_WIDTH/8):0] resp_size_i        ,
60	    input  logic [          REQ_DATA_WIDTH-1:0] resp_data_i        ,
61	    //Sync Interface
62	    output logic                                is_busy_o          ,
63	    output logic                                can_be_inteleaved_o,
64	    output logic [              ADDR_WIDTH-1:0] start_addr_o       ,
65	    output logic [              ADDR_WIDTH-1:0] end_addr_o
66	);
67	
68	    localparam int ELEMENT_ADDR_WIDTH   = $clog2(VECTOR_LANES);
69	    localparam int VREG_ADDR_WIDTH      = $clog2(VECTOR_REGISTERS);
70	    localparam int MAX_MEM_SERVED_LIMIT = REQ_DATA_WIDTH / DATA_WIDTH;
71	    localparam int MAX_RF_SERVED_COUNT  = VECTOR_REGISTERS;
72	    localparam int MAX_SERVED_COUNT     = (VECTOR_REGISTERS > MAX_MEM_SERVED_LIMIT) ? MAX_MEM_SERVED_LIMIT
73	                                                                                    : VECTOR_REGISTERS;
74	
75	    //=======================================================
76	    // REGISTERS
77	    //=======================================================
78	    logic [1:0][VECTOR_LANES-1:0][DATA_WIDTH-1:0]                         scratchpad;
79	
80	    logic [                                    1:0][VECTOR_LANES-1:0] pending_elem        ;
81	    logic [                                    1:0][VECTOR_LANES-1:0] served_elem         ;
82	    logic [                                    1:0][VECTOR_LANES-1:0] active_elem         ;
83	    logic [                      MICROOP_WIDTH-1:0]                   microop_r           ;
84	    logic [                 VECTOR_TICKET_BITS-1:0]                   ticket_r            ;
85	    logic [                    VREG_ADDR_WIDTH-1:0]                   src2_r              ;
86	    logic [                    VREG_ADDR_WIDTH-1:0]                   rdst_r              ;
87	    logic [                                    4:0]                   last_ticket_src2_r  ;
88	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0]                   instr_vl_r          ;
89	    logic [                    VREG_ADDR_WIDTH-1:0]                   current_exp_loop_r  ;
90	    logic [                    VREG_ADDR_WIDTH-1:0]                   max_expansion_r     ;
91	    logic [                 ELEMENT_ADDR_WIDTH-1:0]                   current_pointer_wb_r;
92	    logic [                         ADDR_WIDTH-1:0]                   current_addr_r      ;
93	    logic [                         ADDR_WIDTH-1:0]                   base_addr_r         ;
94	    logic [                         ADDR_WIDTH-1:0]                   stride_r            ;
95	    logic [                                    1:0]                   size_r              ;
96	    logic [                                    1:0]                   memory_op_r         ;
97	    logic [                         ADDR_WIDTH-1:0]                   start_addr_r        ;
98	    logic [                         ADDR_WIDTH-1:0]                   end_addr_r          ;
99	    logic                                                             current_row         ;
100	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_0_rdst          ;
101	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_1_rdst          ;
102	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_0_src           ;
103	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_1_src           ;
104	    //=======================================================
105	    // WIRES
106	    // =======================================================
107	    // logic [                     REQ_DATA_WIDTH-1:0] data_selected           ;
108	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] total_remaining_elements    ;
109	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] nxt_total_remaining_elements;
110	    logic [                   ELEMENT_ADDR_WIDTH:0] loop_remaining_elements     ;
111	    logic [    $clog2(VECTOR_LANES*DATA_WIDTH)-1:0] element_index               ;
112	    logic [                 ELEMENT_ADDR_WIDTH-1:0] nxt_elem                    ;
113	    logic [                   ELEMENT_ADDR_WIDTH:0] el_served_count             ;
114	    logic [                   ELEMENT_ADDR_WIDTH:0] resp_el_count               ;
115	    logic [            VECTOR_LANES*DATA_WIDTH-1:0] data_vector                 ;
116	    logic [                         VECTOR_LANES:0] current_pointer_oh          ;
117	    logic [                         VECTOR_LANES:0] current_served_th           ;
118	    logic [                         VECTOR_LANES:0] resp_elem_th                ;
119	    logic [                         ADDR_WIDTH-1:0] nxt_base_addr               ;
120	    logic [                         ADDR_WIDTH-1:0] nxt_strided_addr            ;
121	    logic [                         ADDR_WIDTH-1:0] nxt_unit_strided_addr       ;
122	    logic [                         ADDR_WIDTH-1:0] current_addr                ;
123	    logic [                         ADDR_WIDTH-1:0] nxt_stride                  ;
124	    logic [                         ADDR_WIDTH-1:0] offset_read                 ;
125	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem            ;
126	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem_loop       ;
127	    logic [        MAX_SERVED_COUNT*DATA_WIDTH-1:0] unpacked_data               ;
128	    logic [                                    1:0] nxt_memory_op               ;
129	    logic [                                    1:0] nxt_size                    ;
130	    logic                                           start_new_instruction       ;
131	    logic                                           maxvl_reached               ;
132	    logic                                           vl_reached                  ;
133	    logic                                           do_reconfigure              ;
134	    logic                                           current_finished            ;
135	    logic                                           currently_idle              ;
136	    logic                                           multi_valid                 ;
137	    logic                                           expansion_finished          ;
138	    logic                                           addr_ready                  ;
139	    logic                                           start_new_loop              ;
140	    logic                                           new_transaction_en          ;
141	    logic                                           request_ready               ;
142	    logic                                           resp_row                    ;
143	    logic                                           writeback_complete          ;
144	    logic                                           row_0_ready                 ;
145	    logic                                           row_1_ready                 ;
146	    logic                                           nxt_row                     ;
147	    logic                                           writeback_row               ;
148	    logic                                           unlock_source               ;
149	    logic                                           unlock_dest                 ;
150	
151	    // Create basic control flow
152	    //=======================================================
153	    assign ready_o             =  currently_idle;
154	    assign is_busy_o           = ~currently_idle;
155	    assign can_be_inteleaved_o = (memory_op_r !== `OP_INDEXED);
156	
157	    //current instruction finished
158	    assign current_finished = ~pending_elem[current_row][nxt_elem] & expansion_finished & new_transaction_en;
159	    //currently no instructions are being served
160	    assign currently_idle = ~|pending_elem & ~|active_elem;
161	
162	    assign expansion_finished = maxvl_reached | vl_reached;
163	    assign maxvl_reached      = (current_exp_loop_r === (max_expansion_r-1));
164	    assign vl_reached         = (((current_exp_loop_r+1) << $clog2(VECTOR_LANES)) >= instr_vl_r);
165	
166	    assign start_new_instruction = valid_in & ready_o & ~instr_in.reconfigure;
167	    assign do_reconfigure        = valid_in & ready_o & instr_in.reconfigure;
168	
169	    // Start from element 0 on the next destination vreg
170	    assign start_new_loop = ~|pending_elem[current_row] & ~expansion_finished & ~|active_elem[nxt_row];
171	
172	    // Create the memory request control signals
173	    assign req_en_o      = request_ready;
174	    assign req_addr_o    = current_addr;
175	    assign req_microop_o = 5'b10000; //REVISIT will change based on instruction
176	    assign req_ticket_o  = {current_row,current_pointer_wb_r};
177	    always_comb begin
178	        unique case (size_r)
179	            `SZ_8   : req_size_o = el_served_count;      //el_served_count * 1
180	            `SZ_16  : req_size_o = el_served_count << 1; //el_served_count * 2
181	            `SZ_32  : req_size_o = el_served_count << 2; //el_served_count * 4
182	            default : req_size_o = 'x;
183	        endcase
184	    end
185	
186	    assign new_transaction_en = req_en_o & grant_i;
187	    assign request_ready      = addr_ready & pending_elem[current_row][current_pointer_wb_r];
188	    assign addr_ready         = (memory_op_r === `OP_INDEXED) ? ~rd_pending_i & ((rd_ticket_i === ticket_r) | (rd_ticket_i === last_ticket_src2_r)) : 1'b1;
189	
190	    // Unlock register signals
191	    assign unlock_en_o     = writeback_complete;
192	    assign unlock_ticket_o = ticket_r;
193	    assign unlock_reg_a_o  = row_0_ready ? row_0_rdst : row_1_rdst;
194	    assign unlock_reg_b_o  = row_0_ready ? row_0_src  : row_1_src;
195	
196	
197	    // Create the writeback signals for the RF
198	    assign wrtbck_req_o       = row_0_ready | row_1_ready;
199	    assign writeback_complete = (row_0_ready | row_1_ready) & wrtbck_grant_i;
200	    assign writeback_row      = row_0_ready ? 1'b0 : 1'b1;
201	
202	    assign row_0_ready = ~|(active_elem[0] ^ served_elem[0]) & |active_elem[0] & (wrtbck_ticket_a_i === ticket_r) & wrtbck_locked_a_i;
203	    assign row_1_ready = ~|(active_elem[1] ^ served_elem[1]) & |active_elem[1] & (wrtbck_ticket_b_i === ticket_r) & wrtbck_locked_b_i;
204	
205	    // Output aliasing
206	    assign wrtbck_en_o     = row_0_ready ? {VECTOR_LANES{writeback_complete}} & served_elem[0] :
207	                                           {VECTOR_LANES{writeback_complete}} & served_elem[1];
208	    assign wrtbck_data_o   = row_0_ready ? scratchpad[0] : scratchpad[1];
209	    assign wrtbck_reg_o    = row_0_ready ? row_0_rdst    : row_1_rdst;
210	    assign wrtbck_ticket_o = ticket_r;
211	    assign wrtbck_reg_a_o  = row_0_rdst;
212	    assign wrtbck_reg_b_o  = row_1_rdst;
213	
214	    // assign the rest of the outputs
215	    assign rd_addr_o    = src2_r;
216	    assign start_addr_o = start_addr_r;
217	    assign end_addr_o   = end_addr_r;
218	    //=======================================================
219	    // Address Generation
220	    //=======================================================
221	    assign multi_valid   = (memory_op_r === `OP_UNIT_STRIDED);
222	    assign element_index = current_pointer_wb_r << 5; //*32
223	    assign offset_read   = rd_data_i[element_index +: DATA_WIDTH];
224	    // Generate next non-multi consecutive address
225	    always_comb begin
226	        case (memory_op_r)
227	            `OP_UNIT_STRIDED : current_addr = current_addr_r;
228	            `OP_STRIDED      : current_addr = current_addr_r;
229	            `OP_INDEXED      : current_addr = base_addr_r + offset_read;
230	            default          : current_addr = 'X;
231	        endcase
232	    end
233	
234	    assign nxt_base_addr    = instr_in.data1 + instr_in.immediate;
235	    assign nxt_strided_addr = current_addr_r + stride_r;
236	    always_comb begin
237	        unique case (size_r)
238	            `SZ_8   : nxt_unit_strided_addr = current_addr_r + el_served_count;
239	            `SZ_16  : nxt_unit_strided_addr = current_addr_r + (el_served_count << 1);
240	            `SZ_32  : nxt_unit_strided_addr = current_addr_r + (el_served_count << 2);
241	            default : nxt_unit_strided_addr = 'X;
242	        endcase
243	    end
244	    //Hold current address
245	    always_ff @(posedge clk) begin
246	        if(start_new_instruction) begin
247	            current_addr_r <= nxt_base_addr;
248	        end else if (new_transaction_en && memory_op_r == `OP_STRIDED) begin
249	            current_addr_r <= nxt_strided_addr;
250	        end else if(new_transaction_en && memory_op_r == `OP_UNIT_STRIDED) begin
251	            current_addr_r <= nxt_unit_strided_addr;
252	        end
253	    end
254	    //Hold base address
255	    always_ff @(posedge clk) begin
256	        if(start_new_instruction) begin
257	            base_addr_r <= nxt_base_addr;
258	        end
259	    end
260	    //Hold stride
261	    assign nxt_stride = instr_in.data2;
262	    always_ff @(posedge clk) begin
263	        if(start_new_instruction) stride_r <= nxt_stride;
264	    end
265	    //Hold mem op size
266	    assign nxt_size = instr_in.microop[`MEM_SZ_RANGE_HI:`MEM_SZ_RANGE_LO];
267	    always_ff @(posedge clk) begin
268	        if(start_new_instruction) size_r <= nxt_size;
269	    end
270	    //=======================================================
271	    // Scratchpad maintenance
272	    //=======================================================
273	    assign resp_row = resp_ticket_i[ELEMENT_ADDR_WIDTH];
274	    // Calculate the elements that have a valid response
275	    always_comb begin
276	        unique case (size_r)
277	            `SZ_8   : resp_el_count = resp_size_i;      //el_served_count * 1
278	            `SZ_16  : resp_el_count = resp_size_i >> 1; //el_served_count * 2
279	            `SZ_32  : resp_el_count = resp_size_i >> 2; //el_served_count * 4
280	            default : resp_el_count = 'x;
281	        endcase
282	    end
283	    assign resp_elem_th = (memory_op_r != `OP_UNIT_STRIDED) ? (1 << resp_ticket_i[ELEMENT_ADDR_WIDTH-1:0]) : ((~('1 << resp_el_count)) << resp_ticket_i[ELEMENT_ADDR_WIDTH-1:0]);
284	    // Unpack the data into elements
285	    always_comb begin
286	        unpacked_data = '0;
287	        if(!multi_valid) begin
288	            unpacked_data[0+:32] = resp_data_i[0 +: 32];
289	        end else begin
290	            for (int i = 0; i < MAX_SERVED_COUNT; i++) begin
291	                unique case (size_r)
292	                    `SZ_8 : begin
293	                        unpacked_data[i*32+:8]    = resp_data_i[i*32 +:8];  //pick 8bits for each elem
294	                        unpacked_data[i*32+8+:24] = 24'b0;                  // pad with 0s per ISA
295	                    end
296	                    `SZ_16 : begin
297	                        unpacked_data[i*32+:16]    = resp_data_i[i*32 +:16]; //pick 16bits for each elem
298	                        unpacked_data[i*32+16+:16] = 16'b0;                  // pad with 0s per ISA
299	                    end
300	                    `SZ_32 : begin
301	                        unpacked_data[i*32+:32] = resp_data_i[i*32 +:32];    //pick 32bits for each elem
302	                    end
303	                    default : begin
304	                        unpacked_data[i*32+:32] = 'X;
305	                    end
306	                endcase
307	            end
308	        end
309	    end
310	    // Shift unpacked data vector to match the elements positions
311	    assign data_vector = unpacked_data << resp_ticket_i[ELEMENT_ADDR_WIDTH-1:0] * 32;
312	    // Store new Data
313	    always_ff @(posedge clk) begin : scratchpad_maint
314	        for (int i = 0; i < VECTOR_LANES; i++) begin
315	            // row 0 maintenance
316	            if(resp_valid_i && !resp_row && resp_elem_th[i]) begin
317	                scratchpad[0][i] <= data_vector[i*32 +: 32];
318	            end
319	            // row 1 maintenance
320	            if(resp_valid_i && resp_row && resp_elem_th[i]) begin
321	                scratchpad[1][i] <= data_vector[i*32 +: 32];
322	            end
323	        end
324	    end
325	    // keep track of the rdst for each row
326	    always_ff @(posedge clk or negedge rst_n) begin
327	        if(~rst_n) begin
328	            row_0_rdst <= 0;
329	            row_1_rdst <= 0;
330	        end else begin
331	            // row 0 maintenance
332	            if(start_new_instruction) begin
333	                row_0_rdst <= instr_in.dst;
334	                row_0_src  <= instr_in.src2;
335	            end else if(start_new_loop && !nxt_row) begin
336	                row_0_rdst <= rdst_r +1;
337	                row_0_src  <= src2_r +1;
338	            end
339	            // row 1 maintenance
340	            if(start_new_loop && nxt_row) begin
341	                row_1_rdst <= rdst_r +1;
342	                row_1_src  <= src2_r +1;
343	            end
344	        end
345	    end
346	    //=======================================================
347	    // Scoreboard maintenance
348	    //=======================================================
349	    always_comb begin : proc_loop_remaining_el
350	        loop_remaining_elements = '0;
351	        for (int i = 0; i < VECTOR_LANES; i++) begin
352	            if (pending_elem[current_row][i]) loop_remaining_elements = loop_remaining_elements +1;
353	        end
354	    end
355	    assign total_remaining_elements     = instr_vl_r - (current_exp_loop_r*VECTOR_LANES);
356	    assign nxt_total_remaining_elements = instr_vl_r - ((current_exp_loop_r+1)*VECTOR_LANES);
357	    always_comb begin : get_served_el_cnt
358	        if (memory_op_r !== `OP_UNIT_STRIDED) begin
359	            el_served_count = 'd1;
360	        end else if (loop_remaining_elements < MAX_SERVED_COUNT) begin
361	            el_served_count = loop_remaining_elements; // remaining < max_width
362	        end else begin
363	            el_served_count = MAX_SERVED_COUNT; // remaining > max_width
364	        end
365	    end
366	
367	    // Maintain current pointer and row
368	    assign nxt_row  = ~current_row;
369	    assign nxt_elem = multi_valid ? (current_pointer_wb_r + el_served_count) : (current_pointer_wb_r +1);
370	    always_ff @(posedge clk or negedge rst_n) begin : current_ptr
371	        if(~rst_n) begin
372	            current_pointer_wb_r <= 0;
373	            current_row          <= 0;
374	        end else begin
375	            if(start_new_instruction) begin
376	                current_pointer_wb_r <= 0;
377	                current_row          <= 0;
378	            end else if(start_new_loop) begin
379	                current_pointer_wb_r <= 0;
380	                current_row          <= nxt_row;
381	            end else if (current_finished) begin
382	                current_pointer_wb_r <= 0;
383	            end else if(new_transaction_en) begin
384	                current_pointer_wb_r <= nxt_elem;
385	            end
386	        end
387	    end
388	
389	    // Create new pending states
390	    always_comb begin : get_new_elem_pending
391	        // next pending state for new instruction
392	        if(instr_in.vl < VECTOR_LANES) begin
393	            nxt_pending_elem = ~('1 << instr_in.vl);
394	        end else begin
395	            nxt_pending_elem = '1;
396	        end
397	        // next pending state for new loop
398	        if(nxt_total_remaining_elements < VECTOR_LANES) begin
399	            nxt_pending_elem_loop = ~('1 << nxt_total_remaining_elements);
400	        end else begin
401	            nxt_pending_elem_loop = '1;
402	        end
403	    end
404	
405	    // Store new pending states
406	    assign current_served_th  = (~('1 << el_served_count)) << current_pointer_wb_r;
407	    assign current_pointer_oh = 1 << current_pointer_wb_r;
408	    always_ff @(posedge clk or negedge rst_n) begin : pending_status
409	        if(~rst_n) begin
410	            pending_elem <= '0;
411	        end else begin
412	            for (int i = 0; i < VECTOR_LANES; i++) begin
413	                //row 0 maintenance
414	                if(start_new_instruction) begin
415	                    pending_elem[0][i] <= nxt_pending_elem[i];
416	                end else if(start_new_loop && !nxt_row) begin
417	                    pending_elem[0][i] <= nxt_pending_elem_loop[i];
418	                end else if(new_transaction_en && current_served_th[i] && multi_valid && !current_row) begin // multi-request
419	                    pending_elem[0][i] <= 1'b0;
420	                end else if(new_transaction_en && current_pointer_oh[i] && !multi_valid && !current_row) begin // single-request
421	                    pending_elem[0][i] <= 1'b0;
422	                end
423	                //row 1 maintenance
424	                if(start_new_instruction) begin
425	                    pending_elem[1][i] <= 1'b0;
426	                end else if(start_new_loop && nxt_row) begin
427	                    pending_elem[1][i] <= nxt_pending_elem_loop[i];
428	                end else if(new_transaction_en && current_served_th[i] && multi_valid && current_row) begin // multi-request
429	                    pending_elem[1][i] <= 1'b0;
430	                end else if(new_transaction_en && current_pointer_oh[i] && !multi_valid && current_row) begin // single-request
431	                    pending_elem[1][i] <= 1'b0;
432	                end
433	            end
434	        end
435	    end
436	    always_ff @(posedge clk or negedge rst_n) begin : active_status
437	        if(~rst_n) begin
438	            active_elem <= '0;
439	        end else begin
440	            for (int i = 0; i < VECTOR_LANES; i++) begin
441	                // row 0 maintenance
442	                if (writeback_complete && !writeback_row) begin
443	                    active_elem[0][i] <= 1'b0;
444	                end else if(start_new_instruction) begin
445	                    active_elem[0][i] <= nxt_pending_elem[i];
446	                end else if(start_new_loop && !nxt_row) begin
447	                    active_elem[0][i] <= nxt_pending_elem_loop[i];
448	                end
449	                // row 1 maintenance
450	                if (writeback_complete && writeback_row) begin
451	                    active_elem[1][i] <= 1'b0;
452	                end else if(start_new_instruction) begin
453	                    active_elem[1][i] <= 1'b0;
454	                end else if(start_new_loop && nxt_row) begin
455	                    active_elem[1][i] <= nxt_pending_elem_loop[i];
456	                end
457	            end
458	        end
459	    end
460	    // Keep track of served elements from memory
461	    always_ff @(posedge clk or negedge rst_n) begin
462	        if(~rst_n) begin
463	            served_elem <= '0;
464	        end else begin
465	            for (int i = 0; i < VECTOR_LANES; i++) begin
466	                // row 0 maintenance
467	                if(start_new_instruction) begin
468	                    served_elem[0][i] <= 1'b0;
469	                end else if(start_new_loop && !nxt_row) begin
470	                    served_elem[0][i] <= 1'b0;
471	                end else if(resp_valid_i && resp_elem_th[i] && !resp_row) begin
472	                    served_elem[0][i] <= 1'b1;
473	                end
474	                // row 1 maintenance
475	                if(start_new_instruction) begin
476	                    served_elem[1][i] <= 1'b0;
477	                end else if(start_new_loop && nxt_row) begin
478	                    served_elem[1][i] <= 1'b0;
479	                end else if(resp_valid_i && resp_elem_th[i] && resp_row) begin
480	                    served_elem[1][i] <= 1'b1;
481	                end
482	            end
483	        end
484	    end
485	
486	    // Keep track of the expanions happening
487	    always_ff @(posedge clk or negedge rst_n) begin : loop_tracking
488	        if(~rst_n) begin
489	            current_exp_loop_r <= 0;
490	        end else begin
491	            if(start_new_instruction) begin
492	                current_exp_loop_r <= 0;
493	                src2_r             <= instr_in.src2;
494	                rdst_r             <= instr_in.dst;
495	            end else if(start_new_loop) begin
496	                current_exp_loop_r <= current_exp_loop_r +1;
497	                src2_r             <= src2_r +1;
498	                rdst_r             <= rdst_r +1;
499	            end
500	        end
501	    end
502	    //Store the max expansion when reconfiguring
503	    always_ff @(posedge clk or negedge rst_n) begin : maxExp
504	        if(~rst_n) begin
505	            max_expansion_r <= 'd1;
506	        end else begin
507	            if(do_reconfigure) begin
508	                max_expansion_r <= instr_in.maxvl >> $clog2(VECTOR_LANES);
509	            end
510	        end
511	    end
512	
513	    //=======================================================
514	    // Capture Instruction Information
515	    always_ff @(posedge clk or negedge rst_n) begin : proc_vl_r
516	        if(~rst_n) begin
517	            instr_vl_r <= VECTOR_LANES;
518	        end else begin
519	            if(start_new_instruction) begin
520	                instr_vl_r <= instr_in.vl;
521	            end
522	        end
523	    end
524	    always_ff @(posedge clk) begin
525	        if(start_new_instruction) begin
526	            microop_r          <= instr_in.microop;
527	            ticket_r           <= instr_in.ticket;
528	            last_ticket_src2_r <= instr_in.last_ticket_src2;
529	        end
530	    end
531	    assign nxt_memory_op = instr_in.microop[`MEM_OP_RANGE_HI:`MEM_OP_RANGE_LO];
532	    always_ff @(posedge clk or negedge rst_n) begin : proc_memory_op_r
533	        if(~rst_n) begin
534	            memory_op_r <= '0;
535	        end else begin
536	            if(start_new_instruction) begin
537	                memory_op_r <= nxt_memory_op;
538	            end
539	        end
540	    end
541	
542	    // calculate start-end addresses for the op
543	    // +- 4 to avoid conflicts due to data sizes
544	    always_ff @(posedge clk or negedge rst_n) begin
545	        if(~rst_n) begin
546	            start_addr_r <= '0;
547	            end_addr_r   <= '1;
548	        end else begin
549	            if(start_new_instruction) begin
550	                start_addr_r <= nxt_base_addr;
551	                if(instr_in.microop[`MEM_OP_RANGE_HI:`MEM_OP_RANGE_LO] !== `OP_INDEXED) begin
552	                    end_addr_r <= nxt_base_addr + ((instr_in.vl -1) * nxt_stride);
553	                end else begin
554	                    end_addr_r <= nxt_base_addr; // cannot calculate end address for `OP_INDEXED ops
555	                end
556	            end
557	        end
558	    end
559	
560	//=======================================================
561	    logic stall_row_0_while_ready, stall_row_1_while_ready;
562	    logic [63:0] total_ld_stalled_due_is;
563	
564	    assign stall_row_0_while_ready = ~|(active_elem[0] ^ served_elem[0]) & |active_elem[0] & (~wrtbck_locked_a_i | wrtbck_ticket_a_i !== ticket_r);
565	    assign stall_row_1_while_ready = ~|(active_elem[1] ^ served_elem[1]) & |active_elem[1] & (~wrtbck_locked_b_i | wrtbck_ticket_b_i !== ticket_r);
566	
567	    always_ff @(posedge clk or negedge rst_n) begin
568	        if(~rst_n) begin
569	            total_ld_stalled_due_is <= 0;
570	        end else begin
571	            if (stall_row_0_while_ready | stall_row_1_while_ready)
572	                total_ld_stalled_due_is <= total_ld_stalled_due_is +1;
573	        end
574	    end
575	
576	
577	`ifdef MODEL_TECH
578	    `include "vmu_ld_eng_sva.sv"
579	`endif
580	
581	endmodule

